for (let i = 0; i < 10; i++) {
  if (i === 5) {
    break;
  }
  console.log(i);
}

for i in range(10):
    if i == 5:
        break
    print(i)

for (int i = 0; i < 10; i++) {
    if (i == 5) {
        break;
    }
    System.out.println(i);
}

DECLARE @i INT = 0;
WHILE @i < 10
BEGIN
    IF @i = 5 BREAK;
    PRINT @i;
    SET @i = @i + 1;
END;
